const body = $input.first().json.body ?? $input.first().json;
const { appointment_id, status, cancellation_reason, cancellation_note, changed_by, note } = body || {};

// Normalize US/UK spelling and casing.
const raw = String(status ?? '').toLowerCase().trim();
const normalized = raw === 'canceled' ? 'cancelled' : raw;

const VALID = ['pending','scheduled','confirmed','arrived','in_progress','completed','no_show','cancelled'];
const VALID_REASONS = ['late','in_time','no_notice','by_doctor','by_clinic','other'];

if (!appointment_id) throw new Error('appointment_id is required');
if (!VALID.includes(normalized)) throw new Error(`Invalid status: ${status}`);

// Cancellation reason validation
let reason = cancellation_reason ? String(cancellation_reason).toLowerCase().trim() : null;
let cnote = cancellation_note ? String(cancellation_note).trim() : null;

if (normalized === 'cancelled') {
  if (!reason) throw new Error("cancellation_reason is required when status='cancelled'");
  if (reason === 'reschedule') throw new Error("reason 'reschedule' can only be set by the reschedule endpoint");
  if (!VALID_REASONS.includes(reason)) throw new Error(`Invalid cancellation_reason: ${cancellation_reason}`);
  if (reason === 'other' && (!cnote || cnote.length === 0)) throw new Error("cancellation_note is required when cancellation_reason='other'");
  if (reason !== 'other') cnote = null;
} else {
  // Not cancelled: clear any incoming reason/note to keep the row consistent.
  reason = null;
  cnote = null;
}

return [{ json: {
  appointment_id: String(appointment_id),
  status: normalized,
  cancellation_reason: reason,
  cancellation_note: cnote,
  changed_by: changed_by ? String(changed_by) : null,
  note: note ? String(note) : null,
} }];

const loaded = $input.all().filter(r => r.json.id);
if (loaded.length === 0) {
  return [{ json: {
    __error: true,
    code: 404,
    message: 'Appointment not found',
  } }];
}

const current = loaded[0].json;
const input = $('Parse Input').first().json;
const from_status = String(current.status || '').toLowerCase();
const to_status = input.status;

if (from_status === to_status) {
  return [{ json: {
    __error: true,
    code: 409,
    message: `Appointment is already in status "${to_status}"`,
  } }];
}

return [{ json: {
  appointment_id: input.appointment_id,
  from_status,
  to_status,
  cancellation_reason: input.cancellation_reason,
  cancellation_note: input.cancellation_note,
  changed_by: input.changed_by,
  note: input.note,
} }];

const rows = $input.all().filter(r => r.json.appointment_id);
if (rows.length === 0) throw new Error('Update failed — no rows returned');
const r = rows[0].json;
return [{ json: {
  success: true,
  code: 200,
  appointment_id: r.appointment_id,
  from_status: r.from_status,
  status: r.to_status,
  cancellation_reason: r.cancellation_reason || null,
  changed_at: r.changed_at,
} }];
